-- ClimbMatch Demo Data
-- Paste this ENTIRE script into Supabase SQL Editor and click Run

ON CONFLICT (id) DO NOTHING;

ON CONFLICT (id) DO NOTHING;

ON CONFLICT (id) DO UPDATE SET
  display_name = EXCLUDED.display_name, photo_url = EXCLUDED.photo_url, home_area = EXCLUDED.home_area,
  climbing_types = EXCLUDED.climbing_types, experience_level = EXCLUDED.experience_level,
  sport_grade_range = EXCLUDED.sport_grade_range, boulder_grade_range = EXCLUDED.boulder_grade_range,
  gear = EXCLUDED.gear, has_car = EXCLUDED.has_car, bio = EXCLUDED.bio, languages = EXCLUDED.languages, phone = EXCLUDED.phone;

